import React from "react"
import Select from 'react-select'
//import Calendar from 'react-select-date'
import { Calendar, DateObject } from "react-multi-date-picker"
import { properties } from '../../properties/properties.js'
import Moment from 'moment'



class CareWebPage extends React.Component {

    constructor(props) {
        super(props);
        this.state = {
            results: [], selectedDate: [], selectedSendTo: [], selectedTime: [], savePageResult: [], screen: 0, savedPage: [], oldValue: {}, edit: false
        };
    }

    handleEditPage = (editItem) => {
      //console.log(editItem)
      document.getElementById("message").value = editItem.message
      this.setState({selectedDate: editItem.dates})
      this.setState({selectedSendTo: editItem.sendTo})
      this.setState({selectedTime: editItem.times})
      this.setState({oldValue: editItem})
      this.setState({edit: true})
    }

    handleDeletePage = (editItem) => {
      this.submitPage({}, editItem)
    }

    handleSendChange = (selectedOptions) => {
      this.setState({selectedSendTo: selectedOptions})
    }

    handleTimeChange = (selectedOptions) => {
      this.setState({selectedTime: selectedOptions})
    }

    handleDateChange = (dates) => {

      var dateArray = []
      for (let i in dates) {
        dateArray.push(new DateObject(dates[i]).format("MM/DD/YYYY"))
      }

      //console.log(dateArray)
      this.setState({selectedDate: dateArray})
      /*
      if (this.state.selectedDate !== date) {
        this.setState({selectedDate: date})
        //console.log(date);var myDate = new Date(date);console.log(myDate);
      }
      */
    }


    submitPage = (pagerequest, oldvalue) => {
      this.setState({screen: 0});

      let headers = new Headers();

      headers.append('Content-Type', 'application/json');
      headers.append('Accept', 'application/json');


      var backUrl = properties.backend + `savepage`
      fetch(backUrl, {
        "method": "POST",
        headers: headers,
        body: JSON.stringify({pagerequest: pagerequest, oldvalue: oldvalue})

      })
      .then(response => response.json())
      .then(response => {
        this.setState({savedPage: response})
        this.setState({screen: 1})
        this.setState({selectedSendTo: []})
        this.setState({selectedTime: []})
        this.setState({selectedDate: []})
        this.setState({oldValue: {}})
        this.setState({edit: false})
      })
      .catch(err => {
        console.log(err);
      });

    }



    handleSendPage = () => {
      //console.log(document.getElementById("message").value)
      //console.log(this.state.selectedSendTo)
      //console.log(this.state.selectedTime)
      //console.log(this.state.selectedDate)
      var pageRequest = {sendTo: this.state.selectedSendTo, message: document.getElementById("message").value, dates: this.state.selectedDate, times: this.state.selectedTime}
      var oldValue = {}

      if (this.state.edit) {
        oldValue = this.state.oldValue
      }
      this.submitPage(pageRequest, oldValue)

    }

        componentDidMount() {


            let headers = new Headers();

            headers.append('Content-Type', 'application/json');
            headers.append('Accept', 'application/json');

            var backUrl = properties.backend + `getSavedPage`

            fetch(backUrl, {
                "method": "GET",
                headers: headers
              })
              .then(response => response.json())
              .then(response => {
                this.setState({savedPage: response})
                this.setState({screen: 1})

              })
              .catch(err => {
                console.log(err);
              });
          }

          render() {


            var header = "Loading ..."




            if (this.state.screen === 1) {
              header = ""
              var content = []
              var rightContent = []
              var leftContent = []

              const options = [
                {value: '5930', label: 'Khanna, Raman'},
                {value: '1837', label: 'Sharpe, Bradley'},
                {value: '1850', label: 'Wu, Ethel'},
                {value: '3135', label: 'Shoeb, Marwa'},
                {value: '2470', label: 'Schaeffer, Sarah'},
                {value: '1889', label: 'Najafi, Nader'},
                {value: '6276', label: 'Lai, Andy'},
                {value: '6548', label: 'Auerbach, Andrew'}

              ]

              const cardiologyOptions = [
                {value: '6709', label: 'Rounding Team, Cardiology A'},
                {value: '6710', label: 'Rounding Team, Cardiology B'}, 
                {value: '6711', label: 'Rounding Team, Cardiology C'}, 
                {value: '6712', label: 'Rounding Team, Cardiology D'}
              ]


              const timeOptions = [
                {value: '830', label: '08:30 am'},
                {value: '845', label: '08:45 am'}, 
                {value: '900', label: '09:00 am'}, 
                {value: '915', label: '09:15 am'},
                {value: '930', label: '09:30 am'},
                {value: '945', lable: '09:45 am'},
                {}
              ]

              const groupedOptions = [
                {label: 'Faculty', options: options},
                {label: 'Cardiology Team', options: cardiologyOptions}
              ]


              rightContent.push(<div style={{marginTop: "50px"}}>Send To:</div>)

              rightContent.push(<div style={{marginTop: "5px", display: "block"}}><Select
                  value={this.state.selectedSendTo}
                  isMulti
                  name="sendTo"
                  options={groupedOptions}
                  className="basic-multi-select"
                  classNamePrefix="select"
                  onChange={this.handleSendChange}
                /></div>)


              rightContent.push(<div style={{marginTop: "15px"}}>Message:</div>)

              rightContent.push(<div style={{marginTop: "5px", display: "block"}}><textarea style={{width: "100%"}} id="message" name="message" rows="5"></textarea></div>)


              var buttonText = "Send Page"
              if (this.state.edit) {
                buttonText = "Edit Page"
              }

              rightContent.push(<div style={{textAlign: "right", marginTop: "15px"}}><button onClick={() => this.handleSendPage()}  id="sendPage" style={{height: "40px", width: "120px", fontSize: "16px", backgroundColor: "yellow" }}>{buttonText}</button></div>)


              leftContent.push(<div>Date To Send:</div>)

              /*
              leftContent.push(<div style={{marginTop: "15px", display: "block"}}><Calendar
              onSelect={(date) => {this.handleDateChange(date);}}
              selectDateType="multiple"
              slotInfo={false}
              showDateInputField={false}
              //onSelect={this.handleDateChange}
              /></div>)
              */
              leftContent.push(<div style={{marginTop: "15px", display: "block"}}><Calendar 
              //value={["10/01/2021","10/02/2021"]}
              //onChange={this.handleDateChange}
              value={this.state.selectedDate}
              onChange={dateArray => {this.handleDateChange(dateArray)}}
              multiple={true}
              format="MM/DD/YYYY"
              numberOfMonths={1}

            /></div>)
              leftContent.push(<div style={{marginTop: "15px"}}>Time To Send:</div>)
              leftContent.push(<div style={{marginTop: "5px", display: "block"}}><Select isMulti name="time" value={this.state.selectedTime} options={timeOptions} onChange={this.handleTimeChange}/></div>)


              content.push(<div style={{display: "flex"}}><div style={{marginRight: "50px", flex: "10%"}}>{leftContent}</div><div style={{flex: "90%"}}>{rightContent}</div></div>)


              //this.state.savedPage

              if (this.state.savedPage.length > 0) {


                content.push(<div style={{marginTop: "50px"}}>Saved Pages<hr></hr></div>)



                for (let i in this.state.savedPage) {
                  var leftPageContent = []
                  var rightPageContent = []

                   var dates = ""
                   for (let j in this.state.savedPage[i].dates) {
                     dates += this.state.savedPage[i].dates[j] + ", "
                   }
                   var sendTo = ""
                   for (let k in this.state.savedPage[i].sendTo) {
                      sendTo += this.state.savedPage[i].sendTo[k].label + "* "
                   }
                  var times = ""
                  for (let l in this.state.savedPage[i].times) {
                    times += this.state.savedPage[i].times[l].label + ", "
                  }




                  leftPageContent.push(<div>Date: {dates.substr(0, dates.length-2)}</div>)
                  leftPageContent.push(<div>Time: {times.substr(0, times.length-2)}</div>)
                  leftPageContent.push(<div>Send To: {sendTo.substr(0, sendTo.length-1)}</div>)
                  leftPageContent.push(<div>Message: {this.state.savedPage[i].message}</div>)

                  rightPageContent.push(<div><button onClick={() => this.handleEditPage(this.state.savedPage[i])}  id="editPage" style={{height: "40px", width: "120px", fontSize: "16px", backgroundColor: "#CCCCCC" }}>Edit</button>&nbsp;<button onClick={() => this.handleDeletePage(this.state.savedPage[i])}  id="deletePage" style={{height: "40px", width: "120px", fontSize: "16px", backgroundColor: "#CCCCCC" }}>Delete</button></div>)


                  content.push(<div style={{display: "flex"}}><div style={{marginRight: "50px", flex: "70%"}}>{leftPageContent}</div><div style={{flex: "30%"}}>{rightPageContent}</div></div>)


                  content.push(<div><hr></hr></div>)

                }





              }

          }



            return (
<div style={{minHeight: "500px", marginLeft: "50px", marginRight: "50px"}}><h2 className="display-4 text-center">{header}</h2>{content}</div>

            );
          }


  };

  export default CareWebPage
